import sys
import json

def add_task(task):
    try:
        with open('notes.json', 'r') as f:
            notes = json.load(f)
    except FileNotFoundError:
        notes = []

    notes.append({"task": task, "done": False})
    with open('notes.json', 'w') as f:
        json.dump(notes, f)

def list_tasks():
    try:
        with open('notes.json', 'r') as f:
            notes = json.load(f)
    except FileNotFoundError:
        notes = []

    for i, note in enumerate(notes):
        status = "Done" if note["done"] else "Pending"
        print(f"{i+1}. {note['task']} - {status}")

def done_task(index):
    try:
        with open('notes.json', 'r') as f:
            notes = json.load(f)
    except FileNotFoundError:
        notes = []

    if 0 <= index < len(notes):
        notes[index]["done"] = True
        with open('notes.json', 'w') as f:
            json.dump(notes, f)
    else:
        print("Invalid task index")

def clear_tasks():
    try:
        with open('notes.json', 'r') as f:
            notes = json.load(f)
    except FileNotFoundError:
        notes = []

    for note in notes:
        note["done"] = True
    with open('notes.json', 'w') as f:
        json.dump(notes, f)

if __name__ == "__main__":
    if len(sys.argv) < 2:
        print("Usage: python main.py [add|list|done|clear] [task]")
        sys.exit(1)

    command = sys.argv[1]
    if command == "add":
        if len(sys.argv) < 3:
            print("Usage: python main.py add \"task description\"")
            sys.exit(1)
        add_task(sys.argv[2])
    elif command == "list":
        list_tasks()
    elif command == "done":
        if len(sys.argv) < 3:
            print("Usage: python main.py done [task index]")
            sys.exit(1)
        try:
            index = int(sys.argv[2]) - 1
            done_task(index)
        except ValueError:
            print("Invalid task index")
    elif command == "clear":
        clear_tasks()
    else:
        print(f"Unknown command: {command}")

