    elif args.operation == "multiply":
        result = multiply(args.a, args.b)
    else:
        try:
            result = divide(args.a, args.b)
        except ValueError as exc:
            print(f"Error: {exc}")
            return

    print(result)


if __name__ == "__main__":
    main()

